export function script(input) {
  const ports = Array.isArray(input.openPorts) ? input.openPorts : [];
  const urls = [];
  for (const item of ports) {
    const host = item?.host || item?.ip;
    const port = Number(item?.port);
    if (!host || !Number.isFinite(port)) continue;
    if ([443, 8443, 9443].includes(port)) urls.push(`https://${host}:${port}`);
    else if ([80, 8080, 8000, 8888, 3000, 5000, 7001, 9000].includes(port)) urls.push(`http://${host}:${port}`);
    else urls.push(`http://${host}:${port}`, `https://${host}:${port}`);
  }
  return { httpTargets: Array.from(new Set(urls)) };
}

export function script(input) {
  const responses = Array.isArray(input.httpResponses) ? input.httpResponses : [];
  const urls = responses.map((item) => item?.url || item?.finalUrl || item?.input).filter((value) => typeof value === 'string' && value.length > 0);
  const unique = Array.from(new Set(urls));
  return { scanTargets: unique.length > 0 ? unique.slice(0, 20) : ['http://no-live-target.invalid'] };
}

export function script(input) {
  const findings = Array.isArray(input.nucleiFindings) ? input.nucleiFindings : [];
  const cvePattern = /CVE-\d{4}-\d+/gi;
  const ids = new Set();
  const hits = [];
  for (const finding of findings) {
    const text = [finding?.templateId, finding?.name, finding?.matchedAt, finding?.host].map((value) => String(value || '')).join(' ');
    const matches = text.match(cvePattern) || [];
    for (const match of matches) ids.add(match.toUpperCase());
    if (matches.length > 0) {
      hits.push({
        cveIds: matches.map((item) => item.toUpperCase()),
        templateId: finding?.templateId || null,
        name: finding?.name || null,
        severity: finding?.severity || null,
        matchedAt: finding?.matchedAt || finding?.url || null
      });
    }
  }
  const cveIds = Array.from(ids).slice(0, 20);
  return { cveIds: cveIds.length > 0 ? cveIds.join(', ') : 'CVE-0000-0000', nucleiCveHits: { hits, extractedCount: cveIds.length } };
}

export function script(input) {
  const nucleiFindings = Array.isArray(input.nucleiFindings) ? input.nucleiFindings : [];
  const nucleiCveHits = input.nucleiCveHits && typeof input.nucleiCveHits === 'object' ? input.nucleiCveHits : { hits: [] };
  const nvdStatus = Number(input.nvdStatus || 0);
  const kevStatus = Number(input.kevStatus || 0);
  const dataSources = {
    nvd: { status: nvdStatus, statusText: input.nvdStatusText || null, ok: nvdStatus >= 200 && nvdStatus < 300 },
    cisaKev: { status: kevStatus, statusText: input.kevStatusText || null, ok: kevStatus >= 200 && kevStatus < 300 }
  };
  const warnings = [];
  if (!dataSources.nvd.ok) warnings.push('NVD enrichment unavailable: ' + (dataSources.nvd.statusText || dataSources.nvd.status || 'unknown error'));
  if (!dataSources.cisaKev.ok) warnings.push('CISA KEV enrichment unavailable: ' + (dataSources.cisaKev.statusText || dataSources.cisaKev.status || 'unknown error'));
  const kevItems = dataSources.cisaKev.ok && Array.isArray(input.kevData?.vulnerabilities) ? input.kevData.vulnerabilities : [];
  const kevById = new Map(kevItems.map((item) => [String(item.cveID || '').toUpperCase(), item]));
  const nvdItems = dataSources.nvd.ok && Array.isArray(input.nvdData?.vulnerabilities) ? input.nvdData.vulnerabilities : [];
  const nvdById = new Map(nvdItems.map((item) => [String(item?.cve?.id || '').toUpperCase(), item?.cve || {}]));
  const severityRank = (severity) => ({ critical: 4, high: 3, medium: 2, low: 1, info: 0 })[String(severity || '').toLowerCase()] || 0;
  const cvePattern = /CVE-\d{4}-\d+/gi;
  const candidates = [];
  for (const finding of nucleiFindings) {
    const text = [finding?.templateId, finding?.name].map((value) => String(value || '')).join(' ');
    const matches = (text.match(cvePattern) || []).map((item) => item.toUpperCase());
    const uniqueIds = Array.from(new Set(matches));
    if (uniqueIds.length === 0) continue;
    for (const cveId of uniqueIds) {
      const kev = kevById.get(cveId) || null;
      const cve = nvdById.get(cveId) || {};
      const descriptions = Array.isArray(cve.descriptions) ? cve.descriptions : [];
      const description = descriptions.find((item) => item?.lang === 'en')?.value || descriptions[0]?.value || null;
      let priorityScore = severityRank(finding?.severity) * 15;
      const priorityReasons = [];
      if (kev) { priorityScore += 100; priorityReasons.push('listed in CISA KEV'); }
      if (finding?.matchedAt) { priorityScore += 25; priorityReasons.push('Nuclei template matched on authorized target'); }
      if (severityRank(finding?.severity) >= 3) { priorityScore += 10; priorityReasons.push(String(finding?.severity || 'unknown').toLowerCase() + ' nuclei severity'); }
      candidates.push({
        title: `${cveId} reachable via Nuclei on authorized target`,
        severity: kev ? 'critical' : String(finding?.severity || 'medium').toLowerCase(),
        cweGuess: null,
        product: kev?.product || kev?.vendorProject || null,
        affectedVersions: [],
        impactSummary: description || 'Known CVE template matched during authorized reachability validation.',
        evidence: {
          source: 'nuclei',
          cveId,
          templateId: finding?.templateId || null,
          name: finding?.name || null,
          matchedAt: finding?.matchedAt || finding?.url || null,
          severity: finding?.severity || null,
          knownExploited: Boolean(kev)
        },
        reproOutline: ['Confirm matched URL is in authorized scope', 'Review Nuclei template and vendor advisory for exploit preconditions', 'Validate non-destructively inside scope before escalation'],
        suggestedCnaPath: 'Existing CVE — coordinate with asset owner for remediation; not a novel CNA assignment candidate',
        mitreCveRequestNotes: 'Validation brief for known CVE reachability, not a new CVE request',
        priorityScore: Math.round(priorityScore * 10) / 10,
        priorityReasons: priorityReasons.length > 0 ? priorityReasons : ['review manually']
      });
    }
  }
  const nonCveFindings = nucleiFindings.filter((finding) => !(String(finding?.templateId || '') + String(finding?.name || '')).match(cvePattern)).map((finding) => ({
    title: finding?.name || finding?.templateId || 'Nuclei finding without CVE id',
    severity: String(finding?.severity || 'medium').toLowerCase(),
    cweGuess: null,
    product: null,
    affectedVersions: [],
    impactSummary: 'Nuclei hit without explicit CVE identifier — lower priority for KEV validation.',
    evidence: { source: 'nuclei', templateId: finding?.templateId || null, matchedAt: finding?.matchedAt || null },
    reproOutline: ['Manual review required'],
    suggestedCnaPath: 'Not a KEV validation lead unless mapped to a CVE manually',
    mitreCveRequestNotes: 'Non-CVE nuclei hit from reachability scan',
    priorityScore: severityRank(finding?.severity) * 5,
    priorityReasons: ['no CVE id in nuclei template metadata']
  }));
  const ranked = [...candidates, ...nonCveFindings].sort((a, b) => b.priorityScore - a.priorityScore).slice(0, 50);
  const kevMatches = ranked.filter((item) => item.evidence?.knownExploited === true);
  const highestSeverity = ranked.reduce((current, item) => severityRank(item.severity) > severityRank(current) ? item.severity : current, null);
  return {
    brief: {
      summary: {
        candidateCount: ranked.length,
        kevReachableCount: kevMatches.length,
        highestSeverity,
        topCandidate: ranked[0]?.title || null,
        liveServices: Array.isArray(input.httpResponses) ? input.httpResponses.length : 0,
        nucleiFindings: nucleiFindings.length
      },
      authorizationNotes: input.authorizationNotes || null,
      dataSources,
      warnings,
      nucleiCveHits,
      candidates: ranked,
      kevMatches,
      nextSteps: ['Prioritize KEV-listed reachable CVEs for immediate remediation review', 'Confirm exploit preconditions against observed service versions', 'Use only non-destructive validation inside authorized scope', 'This brief validates known CVE reachability — not novel CVE assignment']
    }
  };
}
